#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int total=N*N;
        int *vals = (int*)malloc(total*sizeof(int));
        int idx=0;
        for(int i=1;i<=total;i+=2) vals[idx++]=i;
        for(int i=2;i<=total;i+=2) vals[idx++]=i;
        idx=0;
        for(int r=0;r<N;r++){
            for(int c=0;c<N;c++){
                printf("%d", vals[idx++]);
                if(c+1<N) printf(" ");
            }
            printf("\n");
        }
        free(vals);
    }
    return 0;
}

