    while(T--){
        int N; cin>>N;
        int total=N*N;
        vector<int> seq; seq.reserve(total);
        for(int i=1;i<=total;i+=2) seq.push_back(i);
        for(int i=2;i<=total;i+=2) seq.push_back(i);
        int idx=0;
        for(int r=0;r<N;r++){
            for(int c=0;c<N;c++){
                cout<<seq[idx++];
                if(c+1<N) cout<<' ';
            }
            cout<<'\n';
        }
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int total = N * N;
            int[] seq = new int[total];
            int idx = 0;
            for (int i = 1; i <= total; i += 2) seq[idx++] = i;
            for (int i = 2; i <= total; i += 2) seq[idx++] = i;
            idx = 0;
            for (int r = 0; r < N; r++) {
                for (int c = 0; c < N; c++) {
                    out.append(seq[idx++]);
                    if (c + 1 < N) out.append(' ');
                }
                out.append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

