const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let pos = 0;
const T = Number(input[pos++]);
let output = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[pos++]);
  const total = N * N;
  const seq = [];
  for (let i = 1; i <= total; i += 2) seq.push(i);
  for (let i = 2; i <= total; i += 2) seq.push(i);
  let idx = 0;
  for (let r = 0; r < N; r++) {
    const row = seq.slice(idx, idx + N);
    output.push(row.join(' '));
    idx += N;
  }
}
